mapper.select:
SELECT TRAD_NO, CUST_NO, BIZ_TYPE, PRDCT_CD, PRDCT_ID, PRDCT_NM, PRGRSS_STS_CD, ALLIANC_CD, APPRVER_CLERK_NO, APPRVL_DT, AUTHNT_IND, AUTHNT_IND_CD, AUTHNT_REQ_CMPLTN_DT, AUTHNT_REQ_DT, AUTHNT_REQ_EXPIRE_DT, BLK_CLERK_NO, BRNCH_NO, CALL_CNTR_STS_CD, CDD_CNFRM_DT, CDD_REQ_CD, CLERK_NO, CMPLTN_DT, CNCL_DT, CNNCTN_WAY, DEL_OBJ_FLG, ID_CARD_CD, ID_CARD_CMPLTN_DT, ID_CARD_CNT, ID_CARD_REQ_DT, INIT_REGIST_DT, KFB_ACCT_NO, VARCHAR_FORMAT(LST_CHNG_DT, 'YYYY-MM-DD HH24:MI:SS') LST_CHNG_DT, NEW_USER_FLG, REQ_AMT, REA_CD, INTEGRATED_CONSELING_YN FROM NF_TRADINFO_MGT WHERE CUST_NO = #{custNo} AND BIZ_TYPE = #{bizType} AND PRGRSS_STS_CD = 'PRGS' AND TRAD_REG_GB = #{tradRegGb}
AND INTEGRATED_CONSELING_YN = #{integratedConselingYn}
ORDER BY INIT_REGIST_DT DESC FETCH FIRST 1 ROWS ONLY WITH UR

SELECT CM.CUST_NO, TM.TRAD_NO, TM.BIZ_TYPE, TM.PRDCT_CD, TM.PRDCT_ID, TM.PRDCT_NM, TM.PRGRSS_STS_CD, TM.ALLIANC_CD, TM.APPRVER_CLERK_NO, VARCHAR_FORMAT(TM.APPRVL_DT, 'YYYY-MM-DD HH24:MI:SS') APPRVL_DT, TM.AUTHNT_IND, TM.AUTHNT_IND_CD, VARCHAR_FORMAT(TM.AUTHNT_REQ_CMPLTN_DT, 'YYYY-MM-DD HH24:MI:SS') AUTHNT_REQ_CMPLTN_DT, VARCHAR_FORMAT(TM.AUTHNT_REQ_DT, 'YYYY-MM-DD HH24:MI:SS') AUTHNT_REQ_DT, VARCHAR_FORMAT(TM.AUTHNT_REQ_EXPIRE_DT, 'YYYY-MM-DD HH24:MI:SS') AUTHNT_REQ_EXPIRE_DT, TM.BLK_CLERK_NO, TM.BRNCH_NO, TM.CALL_CNTR_STS_CD, VARCHAR_FORMAT(TM.CDD_CNFRM_DT, 'YYYY-MM-DD HH24:MI:SS') CDD_CNFRM_DT, TM.CDD_REQ_CD, TM.CLERK_NO, VARCHAR_FORMAT(TM.CMPLTN_DT, 'YYYY-MM-DD HH24:MI:SS') CMPLTN_DT, VARCHAR_FORMAT(TM.CNCL_DT, 'YYYY-MM-DD HH24:MI:SS') CNCL_DT, TM.CNNCTN_WAY, TM.COPL_CMMN_CLLTRL_IND, TM.DEL_OBJ_FLG, TM.EFFCTV_INT, TM.ELCTRNC_SIGNTR_FLG, TM.EMAIL_ADDR, TM.ERR_CD, TM.ERR_MSG, VARCHAR_FORMAT(TM.EXEC_DT, 'YYYY-MM-DD HH24:MI:SS') EXEC_DT, TM.ID_CARD_CD, VARCHAR_FORMAT(TM.ID_CARD_CMPLTN_DT, 'YYYY-MM-DD HH24:MI:SS') ID_CARD_CMPLTN_DT, TM.ID_CARD_CNT, VARCHAR_FORMAT(TM.ID_CARD_REQ_DT, 'YYYY-MM-DD HH24:MI:SS') ID_CARD_REQ_DT, VARCHAR_FORMAT(TM.INIT_REGIST_DT, 'YYYY-MM-DD HH24:MI:SS') INIT_REGIST_DT, TM.INT_TYPE, TM.KFB_ACCT_NO, TM.KFB_MGT_NO, TM.KTNET_MGT_NO, TM.LOAN_ACCPT_NO, VARCHAR_FORMAT(TM.LOAN_HOPE_DT, 'YYYY-MM-DD HH24:MI:SS') LOAN_HOPE_DT, TM.LOAN_PRD, TM.LOAN_REQ_NO, TM.NEW_USER_FLG, TM.PRVSN_REGIST_FLG, VARCHAR_FORMAT(TM.RDMPTN_DT, 'YYYY-MM-DD HH24:MI:SS') RDMPTN_DT, TM.RDMPTN_MTHD, TM.REQ_AMT, TM.RJCTN_CD, TM.RJCTN_MSG, TM.SEQ_NO, VARCHAR_FORMAT(TM.LST_CHNG_DT, 'YYYY-MM-DD HH24:MI:SS') LST_CHNG_DT, TM.REA_CD, TM.INTEGRATED_CONSELING_YN, TM.OPL_CNSLT_YN FROM NF_CUST_MGT CM, NF_TRADINFO_MGT TM WHERE TM.CUST_NO = CM.CUST_NO AND TM.PRGRSS_STS_CD = 'PRGS' AND CM.CUST_NO = #{custNo} AND TM.TRAD_REG_GB = #{tradRegGb}
AND TM.BIZ_TYPE = #{bizType}
ORDER BY TM.BIZ_TYPE, TM.TRAD_NO WITH UR

mapper.update:
UPDATE
	NF_TRADINFO_MGT
SET
	 KCDD_RES_MSG = #{kcddResMsg}, 
	 CDD_REQ_CD = #{cddReqCd}, 
	PRGRSS_STS_CD = #{prgrssStsCd}
WHERE
	CUST_NO = #{custNo}
	AND TRAD_NO = #{tradNo}
